// ─── Build Tool Definitions from Skill Registry ─────────────────────────────

function buildToolDefs(): ToolDefinition[] {
  return allSkills.map((skill) => ({
    type: 'function' as const,
    function: {
      name: skill.id,
      description: skill.description,
      // Minimal JSON schema representation
      parameters: { type: 'object', properties: {} },
    },
  }))
}

function buildSkillSummaries(): SkillSummary[] {
  return allSkills.map((skill) => ({
    id: skill.id,
    name: skill.name,
    description: skill.description,
  }))
}

// ─── Escalation Detection ────────────────────────────────────────────────────

function needsEscalation(response: string): boolean {
  const escalationPatterns = [
    /speak\s+(?:to|with)\s+(?:a\s+)?(?:human|person|agent|manager|representative)/i,
    /transfer\s+(?:to|me)/i,
    /complaint/i,
    /escalat/i,
    /legal\s+action/i,
    /sue\s+you/i,
    /refund/i,
    /cancel\s+(?:my\s+)?(?:account|subscription|order)/i,
  ]

  return escalationPatterns.some((p) => p.test(response))
}

// ─── Core Execution Loop ────────────────────────────────────────────────────

export async function executeAgent(trigger: ExecutionTrigger): Promise<ExecutionResult> {
  const startTime = Date.now()
  const logs: ExecutionLog[] = []
  let iterationCount = 0
  let toolCallsCount = 0
  let totalCostINR = 0
  let lastProvider = ''
  let lastModel = ''
  let escalation = false

  const log = (
    type: ExecutionLog['type'],
    message: string,
    data?: Record<string, unknown>
  ): void => {
    logs.push({ timestamp: new Date().toISOString(), type, message, data })
  }

  try {
    // ─── Node 1: Load Context ──────────────────────────────────────────
    log('info', `Starting execution for agent ${trigger.agentId}`)

    const agentConfig = await loadAgentConfig(trigger.agentId, trigger.userId)
    log('info', `Loaded agent config: ${agentConfig.name}`)

    const ragContext = await loadRAGContext(trigger.agentId, trigger.message)
    if (ragContext) {
      log('info', `Loaded RAG context (${ragContext.length} chars)`)
    }

    const conversationHistory = await loadConversationHistory(trigger.conversationId)
    log('info', `Loaded ${conversationHistory.length} conversation history messages`)

    // Save the incoming user message (when Supabase is configured)
    await saveMessage(trigger.conversationId, 'user', trigger.message, trigger.agentId)

    // ─── Build System Prompt ───────────────────────────────────────────
    const systemPrompt = buildSystemPrompt({
      agentConfig,
      ragContext: ragContext || undefined,
      conversationHistory,
      currentChannel: trigger.channel,
      customerName: trigger.senderName,
      customerInfo: trigger.senderInfo,
      currentTime: new Date().toLocaleString('en-IN', { timeZone: 'Asia/Kolkata' }),
      availableSkills: buildSkillSummaries(),
    })

    const toolDefs = buildToolDefs()

    // ─── Build Message Array ───────────────────────────────────────────
    const messages: AIMessage[] = [
      { role: 'system', content: systemPrompt },
      ...formatConversationHistory(conversationHistory).map((m) => ({
        role: m.role as 'user' | 'assistant',
        content: m.content,
      })),
      { role: 'user' as const, content: trigger.message },
    ]

    // ─── Safety Config ─────────────────────────────────────────────────
    const safetyConfig: SafetyConfig = {
      ...DEFAULT_SAFETY_CONFIG,
      activeHoursStart: agentConfig.activeHours.start,
      activeHoursEnd: agentConfig.activeHours.end,
    }

    // ─── Node 2-3: LLM Decision Loop ──────────────────────────────────
    while (iterationCount < safetyConfig.maxIterations) {
      // ─── Node 5: Safety Check (every iteration) ─────────────────────
      const safetyState: SafetyState = {
        agentId: trigger.agentId,
        userId: trigger.userId,
        iterationCount,
        runCostINR: totalCostINR,
        actionsThisHour: 0, // Tracked internally by safety module
        actionsToday: 0,
        dailyCostINR: 0,
      }

      const safetyResult = runSafetyChecks(safetyState, safetyConfig)

      if (!safetyResult.allowed) {
        log('safety', `Safety check blocked: ${safetyResult.reason}`)
        return {
          success: false,
          response: 'I apologize, but I am unable to continue processing at this time. A team member will follow up with you shortly.',
          toolCallsCount,
          iterationCount,
          totalCostINR,
          provider: lastProvider,
          model: lastModel,
          logs,
          durationMs: Date.now() - startTime,
          needsEscalation: true,
          error: safetyResult.reason,
        }
      }

      if (safetyResult.level === 'warn') {
        log('safety', `Safety warning: ${safetyResult.reason}`)
      }

      // ─── Node 2: LLM Decision ──────────────────────────────────────
      iterationCount++
      log('info', `Iteration ${iterationCount}: calling LLM`)

      const aiResponse = await callAI({
        messages,
        tools: toolDefs,
        temperature: 0.7,
        maxTokens: 2048,
      })

      lastProvider = aiResponse.provider
      lastModel = aiResponse.model

      const iterCost = estimateCostINR(aiResponse.provider, aiResponse.usage)
      totalCostINR += iterCost
      recordCost(trigger.agentId, iterCost)

      log('info', `LLM response from ${aiResponse.provider}/${aiResponse.model} (cost: ₹${iterCost.toFixed(2)})`, {
        usage: aiResponse.usage as unknown as Record<string, unknown>,
      })

      // ─── Handle Tool Calls ──────────────────────────────────────────
      if (aiResponse.tool_calls.length > 0) {
        // Add assistant message with tool calls
        messages.push({
          role: 'assistant',
          content: aiResponse.content ?? '',
          tool_calls: aiResponse.tool_calls,
        })

        for (const toolCall of aiResponse.tool_calls) {
          toolCallsCount++
          recordAction(trigger.agentId)

          log('tool_call', `Calling tool: ${toolCall.function.name}`, {
            arguments: safeParseJSON(toolCall.function.arguments),
          })

          const skillResult = await executeToolCall(toolCall, {
            agentId: trigger.agentId,
            userId: trigger.userId,
            businessName: agentConfig.businessName,
            channel: trigger.channel,
            conversationId: trigger.conversationId,
          })

          log('tool_result', `Tool ${toolCall.function.name}: ${skillResult.success ? 'success' : 'failed'}`, {
            output: skillResult.output,
            error: skillResult.error,
          })

          // Feed tool result back to the conversation
          messages.push({
            role: 'tool',
            content: skillResult.success
              ? skillResult.output
              : `Error: ${skillResult.error ?? 'Unknown error'}`,
            tool_call_id: toolCall.id,
          })
        }

        // Loop back to Node 2 for next LLM decision
        continue
      }

      // ─── Node 4: Text Output ───────────────────────────────────────
      const responseText = aiResponse.content ?? 'I apologize, but I was unable to generate a response.'

      log('llm_response', `Final response generated (${responseText.length} chars)`)

      // Check for escalation signals
      escalation = needsEscalation(trigger.message) || needsEscalation(responseText)
      if (escalation) {
        log('info', 'Escalation detected — flagging for human review')
      }

      // Send via the appropriate channel
      await sendViaChannel(trigger.channel, trigger.agentId, '', responseText)
      log('output', `Response sent via ${trigger.channel}`)

      // Save assistant response (when Supabase is configured)
      await saveMessage(trigger.conversationId, 'assistant', responseText, trigger.agentId)

      return {
        success: true,
        response: responseText,
        toolCallsCount,
        iterationCount,
        totalCostINR,
        provider: lastProvider,
        model: lastModel,
        logs,
        durationMs: Date.now() - startTime,
        needsEscalation: escalation,
      }
    }

    // If we exhausted all iterations
    log('safety', `Max iterations (${safetyConfig.maxIterations}) reached`)
    const fallbackResponse = 'I have been working on your request but need more time. Let me connect you with a team member who can help further.'

    await sendViaChannel(trigger.channel, trigger.agentId, '', fallbackResponse)
    await saveMessage(trigger.conversationId, 'assistant', fallbackResponse, trigger.agentId)

    return {
      success: true,
      response: fallbackResponse,
      toolCallsCount,
      iterationCount,
      totalCostINR,
      provider: lastProvider,
      model: lastModel,
      logs,
      durationMs: Date.now() - startTime,
      needsEscalation: true,
    }
  } catch (e: unknown) {
    const errorMsg = e instanceof Error ? e.message : String(e)
    log('error', `Execution failed: ${errorMsg}`)

    return {
      success: false,
      response: 'I apologize, but I encountered an issue processing your request. Please try again or contact support.',
      toolCallsCount,
      iterationCount,
      totalCostINR,
      provider: lastProvider,
      model: lastModel,
      logs,
      durationMs: Date.now() - startTime,
      needsEscalation: true,
      error: errorMsg,
    }
  }
}

// ─── Helpers ─────────────────────────────────────────────────────────────────

async function executeToolCall(
  toolCall: ToolCall,
  context: AgentContext
): Promise<{ success: boolean; output: string; error?: string }> {
  try {
    const args = safeParseJSON(toolCall.function.arguments)
    const result = await executeSkill(toolCall.function.name, args, context)
    return { success: result.success, output: result.output, error: result.error }
  } catch (e: unknown) {
    const msg = e instanceof Error ? e.message : String(e)
    return { success: false, output: '', error: msg }
  }
}

function safeParseJSON(str: string): Record<string, unknown> {
  try {
    return JSON.parse(str) as Record<string, unknown>
  } catch {
    return { raw: str }
  }
}

/**
 * Shared Agent Executor — same pattern for all 20 agents
 * RAG + LLM + Action routing
 */

import { createClient } from '@supabase/supabase-js'
import { getAgentPrompt, AgentType, AgentPromptConfig } from './all-prompts'

const supabaseAdmin = createClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL!,
  process.env.SUPABASE_SERVICE_ROLE_KEY!
)

export interface ExecuteInput {
  agentId: string
  agentType: AgentType
  message: string
  channel: 'whatsapp' | 'email' | 'api' | 'widget'
  fromPhone?: string
  fromEmail?: string
  conversationId?: string
  metadata?: Record<string, unknown>
}

export interface ExecuteResult {
  success: boolean
  response: string
  parsedData?: Record<string, unknown>
  action?: string
  conversationId?: string
  error?: string
}

export async function executeAgent(input: ExecuteInput): Promise<ExecuteResult> {
  try {
    // 1. Load agent from DB
    const { data: agent, error: agentError } = await supabaseAdmin
      .from('agents')
      .select('*')
      .eq('id', input.agentId)
      .single()

    if (agentError || !agent) {
      return { success: false, response: '', error: 'Agent not found' }
    }

    // 2. Get or create conversation
    let conversationId = input.conversationId
    if (!conversationId) {
      const identifier = input.fromPhone || input.fromEmail || 'anonymous'
      const { data: existingConv } = await supabaseAdmin
        .from('conversations')
        .select('id')
        .eq('agent_id', input.agentId)
        .eq('customer_identifier', identifier)
        .order('created_at', { ascending: false })
        .limit(1)
        .single()

      if (existingConv) {
        conversationId = existingConv.id
      } else {
        const { data: newConv } = await supabaseAdmin
          .from('conversations')
          .insert({
            agent_id: input.agentId,
            user_id: agent.user_id,
            customer_identifier: identifier,
            channel: input.channel,
            status: 'active',
          })
          .select('id')
          .single()
        conversationId = newConv?.id
      }
    }

    // 3. Store incoming message
    if (conversationId) {
      await supabaseAdmin.from('messages').insert({
        conversation_id: conversationId,
        agent_id: input.agentId,
        role: 'user',
        content: input.message,
        channel: input.channel,
      })
    }

    // 4. Load conversation history (last 10 messages)
    let history: Array<{ role: string; content: string }> = []
    if (conversationId) {
      const { data: msgs } = await supabaseAdmin
        .from('messages')
        .select('role, content')
        .eq('conversation_id', conversationId)
        .order('created_at', { ascending: false })
        .limit(10)
      history = (msgs || []).reverse()
    }

    // 5. Load knowledge base (RAG context)
    let ragContext = ''
    const { data: knowledgeDocs } = await supabaseAdmin
      .from('knowledge_documents')
      .select('content')
      .eq('agent_id', input.agentId)
      .limit(5)
    if (knowledgeDocs && knowledgeDocs.length > 0) {
      ragContext = knowledgeDocs.map((d: { content: string }) => d.content).join('\n\n')
    }

    // 6. Build system prompt
    const promptConfig: AgentPromptConfig = {
      businessName: agent.business_name || agent.name,
      businessKnowledge: ragContext || agent.business_description || 'No specific knowledge uploaded yet.',
      tone: agent.tone || 'professional',
      language: 'English (auto-detect Hinglish)',
      activeHours: `${agent.active_hours_start || 9}am-${agent.active_hours_end || 21}pm IST`,
      agentName: agent.name,
    }

    const systemPrompt = getAgentPrompt(input.agentType, promptConfig)

    // 7. Call LLM via router
    const { callAI } = await import('@/lib/ai/router')
    const messages = [
      { role: 'system' as const, content: systemPrompt },
      ...history.map((m) => ({ role: m.role as 'user' | 'assistant', content: m.content })),
      { role: 'user' as const, content: input.message },
    ]

    const aiResult = await callAI({
      messages,
      temperature: 0.7,
      maxTokens: 800,
    })
    const llmResponse = aiResult.content || "I couldn't generate a response right now."

    // 8. Parse JSON response from LLM
    let parsedData: Record<string, unknown> = {}
    let responseMessage = llmResponse

    try {
      const jsonMatch = llmResponse.match(/\{[\s\S]*\}/)
      if (jsonMatch) {
        parsedData = JSON.parse(jsonMatch[0])
        responseMessage = (parsedData.message as string) || llmResponse
      }
    } catch {
      // LLM returned plain text, use as-is
      responseMessage = llmResponse
    }

    // 9. Store agent response
    if (conversationId) {
      await supabaseAdmin.from('messages').insert({
        conversation_id: conversationId,
        agent_id: input.agentId,
        role: 'agent',
        content: responseMessage,
        channel: input.channel,
      })
    }

    // 10. Log execution
    await supabaseAdmin.from('agent_executions').insert({
      agent_id: input.agentId,
      agent_type: input.agentType,
      input: { message: input.message, channel: input.channel },
      output: { message: responseMessage, data: parsedData },
      conversation_id: conversationId,
    })

    return {
      success: true,
      response: responseMessage,
      parsedData,
      action: parsedData.action as string || parsedData.nextAction as string,
      conversationId,
    }
  } catch (error) {
    console.error('Agent execution error:', error)
    return {
      success: false,
      response: "I'm having a moment. Please try again shortly.",
      error: error instanceof Error ? error.message : 'Unknown error',
    }
  }
}

